import{_ as a,c as i,o as n,ag as p}from"./chunks/framework.D4Vqf8I7.js";const d=JSON.parse('{"title":"The UNIX Pipe Card Game: Process Substitution","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/board/pipes2.md","filePath":"docs/wi/games/board/pipes2.md","lastUpdated":1779716720000}'),e={name:"docs/wi/games/board/pipes2.md"};function t(l,s,r,h,k,o){return n(),i("div",null,s[0]||(s[0]=[p(`<h1 id="the-unix-pipe-card-game-process-substitution" tabindex="-1">The UNIX Pipe Card Game: Process Substitution <a class="header-anchor" href="#the-unix-pipe-card-game-process-substitution" aria-label="Permalink to &quot;The UNIX Pipe Card Game: Process Substitution&quot;">​</a></h1><p><a href="https://punkx.org/unix-pipe-game/ext-0.1/" target="_blank" rel="noreferrer">https://punkx.org/unix-pipe-game/ext-0.1/</a></p><p>Это дополнение к <a href="./../index.html">The Unix Pipe Game</a> с гораздо более сложными задачами, добавляющее команды <code>paste</code>, <code>tr</code>, <code>cut</code>, <code>bc</code>.</p><p>Дополнение предполагает, что родитель знаком с базовыми unix-командами: <code>cat, grep, tail, head, wc, sort, uniq, **paste, tr, cut, bc**</code>. Родитель также должен показать эти команды в действии на компьютере. Если у вас нет UNIX-системы, вы можете использовать <a href="https://bellard.org/jslinux/vm.html?url=alpine-x86.cfg&amp;mem=192" target="_blank" rel="noreferrer">jslinux</a> в вашем браузере.</p><p><a href="https://punkx.org/unix-pipe-game/ext-0.1/photos/deck.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/unix-pipe-game/ext-0.1/photos/deck.jpg" alt="Deck"></a></p><ul><li>распечатайте сами: <a href="unix-pipe-cards-ext-v01.pdf">unix-pipe-cards-v01.pdf</a>, <a href="unix-pipe-ext-v01-box.pdf">unix-pipe-ext-v01-box.pdf</a></li><li>код: <a href="https://github.com/jackdoe/programming-for-kids/tree/master/projects/unix-pipe-game/ext-0.1" target="_blank" rel="noreferrer">unix-pipe-game/ext-0.1</a></li><li>автор: <a href="https://github.com/jackdoe" target="_blank" rel="noreferrer">github.com/jackdoe</a></li><li>соавтор: <a href="https://punkjazz.org/jackie" target="_blank" rel="noreferrer">Jackie</a></li><li>контакт: <a href="mailto:b0000@fastmail.com" target="_blank" rel="noreferrer">b0000@fastmail.com</a></li><li>лицензия: CC BY 4.0</li></ul><blockquote><p><strong>NB:</strong> <mark>Вы не можете играть в это дополнение без базовой игры</mark>. Причина в том, что задачи требуют значительно больше карт, и в одной колоде просто нет места. <mark>Мне жаль</mark>, я действительно пытался сделать колоду самодостаточной, но в итоге решил использовать две колоды, чтобы игра стала интереснее.</p></blockquote><p>Концепция подстановки процессов кратко объясняется в колоде, новые команды также кратко описаны, но я могу объяснить лишь столько в ~1000 символах — этого точно не хватит, чтобы объяснить всё вашим детям, поэтому лучше дать им немного поиграть в командной строке, чтобы почувствовать, как работают <code>paste</code>, <code>tr</code>, <code>cut</code>, <code>bc</code>.</p><hr><h2 id="пример-игрового-раунда" tabindex="-1">Пример игрового раунда <a class="header-anchor" href="#пример-игрового-раунда" aria-label="Permalink to &quot;Пример игрового раунда&quot;">​</a></h2><p><strong>Задача:</strong> <strong>вычислить средний рейтинг: <span style="color:red;">sum(rating)</span> / <span style="color:blue;">(количество фильмов)</span></strong></p><p>Сначала создаём один процесс для <code>cat</code> файла, берём колонку с рейтингами, пропускаем заголовок, соединяем строки через <code>+</code> и передаём в калькулятор. Также нужно посчитать количество фильмов в файле, затем используем <code>paste</code>, чтобы объединить эти выводы через <code>/</code>, и снова передаём в калькулятор:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paste</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d/-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">span </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">style</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;color:red&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cat </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">03.txt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Rating </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> paste</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sd+</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/span&gt;)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">span </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">style</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;color:blue&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cat </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">03.txt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Rating </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/span</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bc</span></span></code></pre></div><p><a href="https://punkx.org/unix-pipe-game/ext-0.1/photos/example.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/unix-pipe-game/ext-0.1/photos/example.jpg" alt="Example"></a></p><hr><h2 id="правила" tabindex="-1">Правила <a class="header-anchor" href="#правила" aria-label="Permalink to &quot;Правила&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Эта игра требует The UNIX Pipes Game</span></span>
<span class="line"><span>версии 0, которую можно получить здесь:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    https://punkx.org/unix-pipe-game/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Она содержит sort, cat и другие команды,</span></span>
<span class="line"><span>необходимые для решения задач в этом</span></span>
<span class="line"><span>дополнении.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Правила те же:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 1. Самый молодой игрок выбирает задачу</span></span>
<span class="line"><span>    из карты задач. Нельзя выбирать одну</span></span>
<span class="line"><span>    и ту же задачу дважды.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 2. Перемешайте карты из обеих колод.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 3. Положите карты рубашкой вверх на стол.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 4. По часовой стрелке каждый игрок берёт</span></span>
<span class="line"><span>    верхнюю карту из колоды и пытается</span></span>
<span class="line"><span>    выполнить задачу.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 5. Первый игрок, выполнивший задачу,</span></span>
<span class="line"><span>    получает очко.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 6. ЕСЛИ задач больше нет, ПЕРЕЙТИ к шагу 8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 7. ПЕРЕЙТИ к шагу 1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; 8. ИГРА ОКОНЧЕНА. ВСТАВЬТЕ МОНЕТУ. ПЕРЕЙТИ к шагу 8</span></span></code></pre></div><h2 id="задачи" tabindex="-1">ЗАДАЧИ <a class="header-anchor" href="#задачи" aria-label="Permalink to &quot;ЗАДАЧИ&quot;">​</a></h2><ul><li><span style="color:red;">*</span> поменять местами колонки рейтинга и названия</li><li><span style="color:green;">*</span> напечатать количество голосов последней строки</li><li><span style="color:red;">*</span> удалить колонки Rank и Votes</li><li><span style="color:green;">*</span> напечатать только колонку с названиями в верхнем регистре</li><li><span style="color:orange;">*</span> напечатать первый и последний фильм</li><li><span style="color:red;">*</span> напечатать разницу в голосах между самым и наименее популярным фильмом</li><li><span style="color:orange;">*</span> просуммировать голоса</li><li><span style="color:red;">*</span> просуммировать голоса фильмов 2016 года</li><li><span style="color:red;">*</span> показать название лучшего по рейтингу фильма, только название, без других колонок</li><li><span style="color:green;">*</span> заменить запятые на табуляцию, удалить пробелы</li><li><span style="color:green;">*</span> напечатать названия как одну гигантскую строку: Sing Interstellar ...</li><li><span style="color:red;">*</span> вычислить средний рейтинг: sum(rating) / (количество фильмов)</li></ul>`,19)]))}const g=a(e,[["render",t]]);export{d as __pageData,g as default};
